ked) } // Fetch All Double Map Storage { storage := staPallet.StorageErasValidatorPrefs{} era := uint32(299) val, err := storage.FetchAll(&blockStorage, era) if err != nil { panic(err) } for i := 0; i < len(val); i++ { println("Era: ", val[i].Key1) println("Address: ", val[i].Key2.ToHuman()) println("Commission: ", val[i].Value.Commission.ToHuman()) println("Blocked: ", val[i].Value.Blocked) if i >= 2 { break } } }
