Example: type ComplexEnum struct { VariantIndex uint8 Day prim.Option[uint16] Month prim.Option[uint8] Year prim.Option[uint32]
} func (this ComplexEnum) ToString() string { switch this.VariantIndex { case 0: return "Nothing" case 1: return fmt.Sprintf("Set: %v", this.Day.Unwrap()) case 2: return fmt.Sprintf("Set: %v", this.Month.Unwrap()) case 3: return fmt.Sprintf("Set: %v", this.Year.Unwrap()) default: panic("Unknown ComplexEnum Variant Index") }
} func (this *ComplexEnum) EncodeTo(dest *string) { prim.Encoder.EncodeTo(this.VariantIndex, dest) if this.Day.IsSome() { prim.Encoder.EncodeTo(this.Day.Unwrap(), dest) } if this.Month.IsSome() { prim.Encoder.EncodeTo(this.Month.Unwrap(), dest) } if this.Year.IsSome() { prim.Encoder.EncodeTo(this.Year.Unwrap(), dest) }
} func (this *ComplexEnum) Decode(decoder *prim.Decoder) error { *this = ComplexEnum{} if err := decoder.Decode(&this.VariantIndex); err != nil { return err } switch this.VariantIndex { case 0: case 1: var t uint16 if err := decoder.Decode(&t); err != nil { return err } this.Day.Set(t) case 2: var t uint8 if err := decoder.Decode(&t); err != nil { return err } this.Month.Set(t) case 3: var t uint32 if err := decoder.Decode(&t); err != nil { return err } this.Year.Set(t) default: return errors.New("Unknown ComplexEnum Variant Index while Decoding") } return nil
} When at least one variant has additional data attach to it, we are forced to created on our encode and decode methods. First of all the additional variant data needs to be stored as an option, and the field member should have the same name as the variant itself. In this case Day, Month, Year now carry additional data and that's why there are three fields with the same name in our enum struct. The EncodeTo method manually scale encodes the data. The VariantIndex is a u8 so it's going to be encoded like that. The rest depends on what option has been set. If VariantIndex is set to 1, and Day is set to 25, both will be encoded correctly. Take care: If you set up the wrong option or set up more than one option then the transaction will fail. It's up to you to be diligent and not mess up. Example of correct setup: enum := ComplexEnum{}
enum.VariantIndex = 2
enum.Month.Set(12) Example of incorrect setup: // VariantIndex out of range
enum := ComplexEnum{}
enum.VariantIndex = 125 // VariantIndex and data not matching
enum.VariantIndex = 0
enum.Year.Set(1990) // Too many data fields are set
enum.VariantIndex = 1
enum.Day.Set(24)
enum.Year.Set(1990) There isn't much room for errors in the Decode method unless the devs messed it up.

